from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of Triple objects about an artist into a single fluent sentence.
    Handles a variety of predicates with simple natural‑language templates.
    """
    if not triples:
        return ""

    parts: list[str] = []
    for t in triples:
        s, p, o = t.subject, t.predicate, t.object

        # Basic templates for common predicates
        if p == "birthDate":
            parts.append(f"{s} was born on {o}")
        elif p == "birthYear":
            parts.append(f"{s} was born in {o}")
        elif p == "deathDate":
            parts.append(f"{s} died on {o}")
        elif p == "deathPlace":
            parts.append(f"{s} died in {o}")
        elif p == "origin":
            parts.append(f"{s} is from {o}")
        elif p == "nationality":
            parts.append(f"{s} is {o}")
        elif p == "genre":
            parts.append(f"{s} performs {o}")
        elif p == "instrument":
            parts.append(f"{s} plays the {o}")
        elif p == "occupation":
            parts.append(f"{s} works as {o}")
        elif p == "recordLabel":
            parts.append(f"{s} is signed to {o}")
        elif p == "associatedBand/associatedMusicalArtist":
            parts.append(f"{s} is associated with {o}")
        elif p == "background":
            parts.append(f"{s} has a background as {o}")
        elif p == "activeYearsStartYear":
            parts.append(f"{s} started their career in {o}")
        elif p == "activeYearsEndYear":
            parts.append(f"{s} ended their active years in {o}")
        else:
            # Fallback generic phrasing
            parts.append(f"{s} {p} {o}")

    # Join the fragments into one sentence
    sentence = "; ".join(parts) + "."
    # Capitalise the first character
    return sentence[0].upper() + sentence[1:]

# EVOLVE-BLOCK-END

